public void add(ID3v2Frame frame) throws IllegalArgumentException {
	//if (frame.get(FrameProperty.MAIN).toString().equals(""))
	//	throw new IllegalArgumentException("FrameProperty.MAIN must not be empty");
	if (frames.contains(frame)) {
		throw new IllegalArgumentException("frame is already part of the tag.");
	}

	frame.setTag(this);
	frames.add(frame);

	int frameCount = getFrameCount();
	changeSupport.firePropertyChange(
		FRAME_COUNT_PROPERTY,
		frameCount - 1,
		frameCount);

	sizeChanged = true;
}

public boolean remove(ID3v2Frame frame) {
	boolean success = frames.remove(frame);

	if (success) {
		frame.setTag(null);
		int frameCount = getFrameCount();
		changeSupport.firePropertyChange(
			FRAME_COUNT_PROPERTY,
			frameCount + 1,
			frameCount);

		sizeChanged = true;
	}
	return success;
}

