public void removeAll(int type) {
	for (int i = 0; i < frames.size(); ++i) {
		ID3v2Frame frame = (ID3v2Frame) frames.elementAt(i);
		if (frame.getType() == type) {
			remove(frame);
			break;
		}
	}
}

public void removeAll() {
	int frameCount = frames.size();
	frames.clear();
	if (frameCount > 0) {
		changeSupport.firePropertyChange(
			FRAME_COUNT_PROPERTY,
			frameCount,
			0);
	}
}

public void recalculateSize() {
	try {
		this.contentSize = spec.getSize(this);
	} catch (RuntimeException e) {
		logger.error("ID3v2Tag::recalculateSize(): "
			+ "Unexpected exception in spec "+spec+" getSize(ID3v2Tag).\n"
			+ "Spec is probably buggy.", e);
		throw e;
	}
	sizeChanged = false;
}

public int getSize() {
	recalculateSizeIfNeccessary();
	if (preferredSizeMode == ID3Constants.ABSOLUTE)
		return (contentSize < preferredSize ? preferredSize : contentSize);
	else /* if (preferredSizeType == ID3Constants.RELATIVE) */
		return contentSize + preferredSize;
}

