public V extractMin() {
	if (isEmpty()) {
		return null;
	}
	V tmp = heap.get(0);
	valueIndexMap.remove(tmp);
	valueKeyMap.remove(tmp);
	heap.set(0, heap.get(size() - 1));
	valueIndexMap.put(heap.get(0), 0);
	heap.remove(size() - 1);
	siftDown(0);
	return tmp;
}

