public void unmark() {
	for (Iterator<EdgePresentation> it = markedEdges.iterator(); it.hasNext();) {
		EdgePresentation ep = it.next();
		ep.unmark();
		it.remove();
	}
	verticesData.clear();
	edgesData.clear();
	markedVertices.clear();
	fireVisualChandesCancelled();
}

