public TypeFilteredPropertyPredicate addType(Class type){
  try{
    final BeanType btype = BeanType.instance(type);
    final Set names = btype.getPropertyNames();
    for(Iterator it=names.iterator();it.hasNext();){
      final String key = (String)it.next();
      final Method writer = btype.getWriter(key);
      if(writer!=null){
        addProperty(writer.getDeclaringClass(), key);
      }
    }
  }
  catch(IntrospectionException e){}
  return this;
}

public TypeFilteredPropertyPredicate addProperty(Class type, String key){
  final Object slot = filter_types.get(key);
  if(slot==null){
    filter_types.put(key, type);
  }
  else{
    final ArrayList list = toArrayList(slot);
    list.add(type);
    filter_types.put(key, list);
  }
  return this;
}

